using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "AppDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Session>(entity =>
        {
            entity.ToContainer("Sessions");

            // Fix 1: EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so explicitly preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Fix 2: EF Core 9 no longer includes the discriminator in the JSON "id" property.
            // Existing documents have the old compound format (e.g., "Session|abc123").
            // Preserve old format so existing documents remain accessible.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}

class Session
{
    public string Id { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public DateTime StartedAt { get; set; }
}

// Fix 3: EF Core 9 Cosmos DB provider no longer supports synchronous I/O.
// All sync methods (ToList, SaveChanges, First, etc.) now throw.
// Use async equivalents instead.
class CosmosSessionService
{
    private readonly CosmosDbContext _db;

    public CosmosSessionService(CosmosDbContext db) => _db = db;

    // Before (BREAKS in EF Core 9):
    //   var sessions = _db.Sessions.Where(s => s.StartedAt > cutoff).ToList();
    //   _db.SaveChanges();
    //
    // After: use async methods
    public async Task<List<Session>> GetRecentSessionsAsync(DateTime cutoff)
    {
        return await _db.Sessions
            .Where(s => s.StartedAt > cutoff)
            .ToListAsync();
    }

    public async Task AddSessionAsync(Session session)
    {
        _db.Sessions.Add(session);
        await _db.SaveChangesAsync();
    }
}

